// import mathImage from "../../assets/photos/cards/mathsLogo.png"

import { useEffect } from "react";

interface Course {
  name: string;
  imagePath: string;
  url: string;
  status: boolean; 
}

export default function CourseCard({ course }: {course: Course}) {
  useEffect(() => {
    console.log(course.imagePath);
  }, []);
  return (
    <div className = "courseCard">
      <img 
        src = {course.imagePath}
        alt = "Error in loading"
      />
      <p> {course.name} </p>
      <p> {course.imagePath} </p>
      <button className = "courseSignUp"> Записатся </button>
    </div>
  )
}
